/**
 * Generate GitLab firewall config.
 *
 * Data source: https://docs.gitlab.com/api/rest/authentication/
 *
 * GitLab uses PRIVATE-TOKEN header for authentication.
 * Token format (gitleaks: gitlab-pat): glpat- + 20 word chars
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.gitlab.com/api/rest/authentication/";
// Format: glpat- + [\w-]{20} (gitleaks: gitlab-pat)
const PLACEHOLDER_VALUE = "glpat-CoffeeSafeLocalCoffe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from GitLab API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:gitlab",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const gitlabFirewall = {",
    '  name: "gitlab",',
    '  description: "GitLab API",',
    "  placeholders: {",
    `    GITLAB_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://gitlab.com/api",',
    "      auth: {",
    "        headers: {",
    '          "PRIVATE-TOKEN": "${{ secrets.GITLAB_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating GitLab firewall config...");
  const ts = generateTypeScript();
  writeOutput("gitlab", ts, import.meta.dirname);
}
